class User {
  final String id;
  final String email;
  final String name;
  final String? profileImage;

  User({
    required this.id,
    required this.email,
    required this.name,
    this.profileImage,
  });

  Map<String, dynamic> toJson() {
    return {
      'id': id,
      'email': email,
      'name': name,
      'profileImage': profileImage,
    };
  }

  factory User.fromJson(Map<String, dynamic> json) {
    return User(
      id: json['id'],
      email: json['email'],
      name: json['name'],
      profileImage: json['profileImage'],
    );
  }
}

class AuthTokens {
  final String accessToken;
  final String refreshToken;
  final DateTime expiresAt;

  AuthTokens({
    required this.accessToken,
    required this.refreshToken,
    required this.expiresAt,
  });

  Map<String, dynamic> toJson() {
    return {
      'accessToken': accessToken,
      'refreshToken': refreshToken,
      'expiresAt': expiresAt.toIso8601String(),
    };
  }

  factory AuthTokens.fromJson(Map<String, dynamic> json) {
    return AuthTokens(
      accessToken: json['accessToken'],
      refreshToken: json['refreshToken'],
      expiresAt: DateTime.parse(json['expiresAt']),
    );
  }

  bool get isExpired => DateTime.now().isAfter(expiresAt);
}

class AuthManager extends ChangeNotifier {
  static const String _keyAuthTokens = 'auth_tokens';
  static const String _keyUserData = 'user_data';
  static const String _keyIsLoggedIn = 'is_logged_in';

  SharedPreferences? _prefs;
  User? _currentUser;
  AuthTokens? _authTokens;
  bool _isInitialized = false;
  bool _isLoggedIn = false;

  User? get currentUser => _currentUser;
  AuthTokens? get authTokens => _authTokens;
  bool get isLoggedIn => _isLoggedIn;
  bool get isInitialized => _isInitialized;
  String? get accessToken => _authTokens?.accessToken;

  Future<void> initialize() async {
    if (_isInitialized) return;

    _prefs = await SharedPreferences.getInstance();
    await _loadSession();
    _isInitialized = true;
    notifyListeners();
  }

  Future<void> _loadSession() async {
    try {
      _isLoggedIn = _prefs?.getBool(_keyIsLoggedIn) ?? false;

      if (_isLoggedIn) {
        final tokensJson = _prefs?.getString(_keyAuthTokens);
        final userJson = _prefs?.getString(_keyUserData);

        if (tokensJson != null && userJson != null) {
          _authTokens = AuthTokens.fromJson(jsonDecode(tokensJson));
          _currentUser = User.fromJson(jsonDecode(userJson));

          if (_authTokens!.isExpired) {
            await logout();
          }
        } else {
          await logout();
        }
      }
    } catch (e) {
      await logout();
    }
  }

  Future<bool> login({
    required String email,
    required String password,
  }) async {
    try {
      final tokens = await _performLogin(email, password);
      final user = await _fetchUserData(tokens.accessToken);

      await _saveSession(tokens, user);

      _authTokens = tokens;
      _currentUser = user;
      _isLoggedIn = true;

      notifyListeners();
      return true;
    } catch (e) {
      return false;
    }
  }

  Future<AuthTokens> _performLogin(String email, String password) async {
    await Future.delayed(Duration(seconds: 1));

    return AuthTokens(
      accessToken: 'mock_access_token_${DateTime.now().millisecondsSinceEpoch}',
      refreshToken: 'mock_refresh_token_${DateTime.now().millisecondsSinceEpoch}',
      expiresAt: DateTime.now().add(Duration(hours: 24)),
    );
  }

  Future<User> _fetchUserData(String accessToken) async {
    await Future.delayed(Duration(milliseconds: 500));

    return User(
      id: 'user_123',
      email: 'user@example.com',
      name: 'John Doe',
      profileImage: 'https://example.com/profile.jpg',
    );
  }

  Future<void> _saveSession(AuthTokens tokens, User user) async {
    await _prefs?.setString(_keyAuthTokens, jsonEncode(tokens.toJson()));
    await _prefs?.setString(_keyUserData, jsonEncode(user.toJson()));
    await _prefs?.setBool(_keyIsLoggedIn, true);
  }

  Future<bool> refreshToken() async {
    if (_authTokens == null) return false;

    try {
      final newTokens = await _performTokenRefresh(_authTokens!.refreshToken);

      await _prefs?.setString(_keyAuthTokens, jsonEncode(newTokens.toJson()));

      _authTokens = newTokens;
      notifyListeners();
      return true;
    } catch (e) {
      await logout();
      return false;
    }
  }

  Future<AuthTokens> _performTokenRefresh(String refreshToken) async {
    await Future.delayed(Duration(milliseconds: 500));

    return AuthTokens(
      accessToken: 'refreshed_access_token_${DateTime.now().millisecondsSinceEpoch}',
      refreshToken: refreshToken,
      expiresAt: DateTime.now().add(Duration(hours: 24)),
    );
  }

  Future<void> updateUserData(User user) async {
    _currentUser = user;
    await _prefs?.setString(_keyUserData, jsonEncode(user.toJson()));
    notifyListeners();
  }

  Future<void> logout() async {
    await _prefs?.remove(_keyAuthTokens);
    await _prefs?.remove(_keyUserData);
    await _prefs?.setBool(_keyIsLoggedIn, false);

    _authTokens = null;
    _currentUser = null;
    _isLoggedIn = false;

    notifyListeners();
  }

  Future<void> clearAllData() async {
    await _prefs?.clear();
    _authTokens = null;
    _currentUser = null;
    _isLoggedIn = false;
    notifyListeners();
  }
}

