class ChangeNotifierProvider extends InheritedNotifier<AuthManager> {
  ChangeNotifierProvider({
    Key? key,
    required AuthManager create,
    required Widget child,
  }) : super(key: key, notifier: create, child: child);

  static AuthManager of(BuildContext context) {
    return context
        .dependOnInheritedWidgetOfExactType<ChangeNotifierProvider>()!
        .notifier!;
  }
}

class AuthWrapper extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    final authManager = ChangeNotifierProvider.of(context);

    if (!authManager.isInitialized) {
      return Scaffold(
        body: Center(
          child: CircularProgressIndicator(),
        ),
      );
    }

    return authManager.isLoggedIn ? HomeScreen() : LoginScreen();
  }
}

class LoginScreen extends StatefulWidget {
